import{_ as e,o as t,c as a,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Branch Dashboard Navigation Update","description":"","frontmatter":{"title":"Branch Dashboard Navigation Update","slug":"new-navigation-structure"},"headers":[],"relativePath":"account-hub/new-navigation-structure.md","filePath":"account-hub/new-navigation-structure.md"}'),r={name:"account-hub/new-navigation-structure.md"};function s(i,n,g,l,c,d){return t(),a("div",null,[...n[0]||(n[0]=[o('<p><a href="../../../assets/media/files/Branch-nav-changes.mp4">null</a></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>We’ve updated the <a href="https://branch.dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a> navigation to make it more modern, intuitive, and easier to navigate. These changes are designed to help you find what you need faster by improving the overall experience.</p><h2 id="new-sections" tabindex="-1">New sections <a class="header-anchor" href="#new-sections" aria-label="Permalink to &quot;New sections&quot;">​</a></h2><p>There are now four main sections:</p><ul><li><strong>Analysis</strong>: View metrics for campaigns, fraud, ads, and more.</li><li><strong>Campaigns</strong>: Manage links, Journeys, QR codes, DeepViews, and more.</li><li><strong>Configure</strong>: Manage app configuration, ROI Hub, ad partners, and more.</li><li><strong>Account</strong>: Manage your account and team settings.</li></ul><h2 id="main-navigation-changes" tabindex="-1">Main navigation changes <a class="header-anchor" href="#main-navigation-changes" aria-label="Permalink to &quot;Main navigation changes&quot;">​</a></h2><ul><li>Added <strong>Analysis</strong> and <strong>Campaign</strong> sections to organize pages around core workflows</li><li>Removed <strong>Cross-Channel Analytics</strong> section</li><li>Moved <strong>Summary</strong>, <strong>Sources</strong>, and <strong>Live View</strong> to the <strong>Overview</strong> page in the <strong>Analysis</strong> section</li><li>Moved <strong>Ads Analytics</strong> to the <strong>Analysis</strong> section</li><li>Moved <strong>ROI Hub</strong> to the <strong>Configuration</strong> section</li><li>Moved <strong>Journeys</strong>, <strong>Emails</strong>, <strong>LinkHub</strong>, <strong>QR Codes</strong>, and <strong>Engagement Builder</strong> to the <strong>Campaigns</strong> section</li><li>Moved <strong>Exports</strong> to the <strong>Configure</strong> section</li><li>Moved configuration items to the <strong>App Settings</strong> page in the <strong>Configure</strong> section</li></ul><h2 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h2><p>View the following image to see the improvements:</p><p>.png)</p>',11)])])}const p=e(r,[["render",s]]);export{u as __pageData,p as default};
